import { HTMLBnumFragment } from 'components/atoms';
import BnumElementInternal from 'components/bnum-element-states';
import { Define } from 'core/decorators';
import { Listen } from 'core/decorators/listen';
import style from './bnum-avatar-action.less';
import { Listener } from 'core/decorators/listener';
import JsEvent from '@rotomeca/event';
import { Nullable } from '@rotomeca/utils';

const TEMPLATE = (
	<HTMLBnumFragment>
		<span id="avatar">
			<slot name="avatar"></slot>
		</span>
		<span id="action">
			<slot name="action"></slot>
		</span>
	</HTMLBnumFragment>
);

@Define({ template: TEMPLATE, styles: style, tag: 'bnum-avatar-action' })
export class HTMLBnumAvatarAction extends BnumElementInternal {
	@Listener() accessor onEnter!: JsEvent<
		(caller: HTMLBnumAvatarAction) => void
	>;
	@Listener() accessor onLeave!: JsEvent<
		(caller: HTMLBnumAvatarAction) => void
	>;

	constructor() {
		super();
	}

	protected _p_attach(): void {
		super._p_attach();

		this.#_addListeners();
	}

	#_addListeners() {
		this._handleOnHover();
		this._handleOnLeave();

		return this;
	}

	@Listen('mouseenter')
	private _handleOnHover() {
		return this._handleOnMouseEnter;
	}

	@Listen('mouseleave')
	private _handleOnLeave() {
		return this._handleOnMouseLeave;
	}

	private _handleOnMouseEnter() {
		if (this.onEnter.haveEvents()) this.onEnter.call(this);

		this._p_addState('action');
	}

	private _handleOnMouseLeave() {
		if (this.onLeave.haveEvents()) this.onLeave.call(this);

		this._p_removeState('action');
	}

	static Create({
		avatar = null,
		action = null,
	}: {
		avatar?: Nullable<HTMLElement>;
		action?: Nullable<HTMLElement>;
	} = {}): HTMLBnumAvatarAction {
		const node = document.createElement(this.TAG) as HTMLBnumAvatarAction;

		if (avatar) {
			if (!avatar.hasAttribute('slot')) avatar.setAttribute('slot', 'avatar');

			node.appendChild(avatar);
		}

		if (action) {
			if (!action.hasAttribute('slot')) action.setAttribute('slot', 'action');

			node.appendChild(action);
		}

		return node;
	}
}
